          background: #667eea;
          border-color: #667eea;
          color: white;
        }

        .chat-message.user .message-avatar {
          background: #10b981;
          border-color: #10b981;
          color: white;
        }

        .message-content-wrapper {
          max-width: 280px;
        }

        .message-content {
          background: white;
          padding: 16px;
          border-radius: 18px;
          border-bottom-left-radius: 4px;
