          font-size: 14px;
          line-height: 1.5;
          color: #374151;
        }

        .chat-message.user .message-text {
          color: white;
        }

        .message-line-emphasis {
          font-weight: 600;
          margin: 8px 0;
        }

        .message-line-indent {
          margin-left: 20px;
          margin: 4px 0 4px 20px;
        }

        .message-data {
          margin-top: 12px;
          border-top: 1px solid #e5e7eb;
          padding-top: 12px;
        }

        .message-data details {
          font-size: 12px;
        }

        .message-data summary {
          cursor: pointer;
          color: #667eea;
          font-weight: 500;
        }

        .message-data pre {
          margin-top: 8px;
          padding: 12px;
          background: #f9fafb;
          border-radius: 8px;
          font-size: 11px;
          overflow: auto;
          max-height: 200px;
        }

        .message-meta {
          display: flex;
