        }

        .send-message-btn:disabled {
          background: #d1d5db;
          cursor: not-allowed;
        }

        /* Dashboard Content */
        .dashboard-content {
          max-width: 1200px;
          margin: 0 auto;
          padding: 32px;
        }

        /* Insights Section */
        .insights-section {
          margin-bottom: 32px;
        }

        .insights-title {
          font-size: 18px;
          font-weight: 600;
          color: #111827;
          margin-bottom: 16px;
        }

        .insights-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
          gap: 16px;
        }

        .insight-card {
          background: white;
          padding: 20px;
          border-radius: 16px;
          border-left: 4px solid;
          display: flex;
          align-items: center;
          gap: 16px;
          cursor: pointer;
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
        }

        .insight-card:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
        }

        .insight-card.info {
          border-left-color: #3b82f6;
        }

        .insight-card.warning {
          border-left-color: #f59e0b;
        }

        .insight-card.success {
          border-left-color: #10b981;
        }

        .insight-icon-wrapper {
          width: 40px;
          height: 40px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
