        .insight-card.info .insight-icon-wrapper {
          background: #dbeafe;
          color: #3b82f6;
        }

        .insight-card.warning .insight-icon-wrapper {
          background: #fef3c7;
          color: #f59e0b;
        }

        .insight-card.success .insight-icon-wrapper {
          background: #d1fae5;
          color: #10b981;
        }

        .insight-text-content {
          flex: 1;
          font-size: 14px;
          color: #4b5563;
          line-height: 1.5;
