import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { 
  Loader2, 
  Send, 
  Bot, 
  X, 
  ChevronRight, 
  BookOpen, 
  Calendar, 
  CreditCard, 
  CheckCircle,
  AlertCircle,
  Clock,
  TrendingUp,
  MessageSquare,
  User,
  RefreshCw,
  Trash2
} from 'lucide-react';

const StudentDashboard = () => {
  const [payload, setPayload] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAllSemesters, setShowAllSemesters] = useState(false);
  
  // Chatbot State
  const [chatbotOpen, setChatbotOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [userInput, setUserInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [chatHistory, setChatHistory] = useState([]);
  const messagesEndRef = useRef(null);
  const chatContainerRef = useRef(null);

  const API_BASE_URL = 'http://localhost:65000';
  const CHATBOT_API_URL = `${API_BASE_URL}/api/chatbot`;

  useEffect(() => {
    loadDashboard();
    // eslint-disable-next-line
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const loadDashboard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/students/getStudentDashboard`, {
        withCredentials: true
      });
      setPayload(res.data);
      
      // Preload chatbot with student context
      if (res.data.student) {
        initializeChatbotWithContext(res.data);
      }
    } catch (err) {
      console.error('Dashboard load error:', err);
      setError(err.response?.data?.message || 'Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const initializeChatbotWithContext = (studentData) => {
    const welcomeMessage = {
      id: Date.now(),
      type: 'ai',
      content: `Hi ${studentData.student.name.fullName}! 👋 I'm your AI assistant. I can help you with:\n\n• Academic progress & GPA\n• Fee information & payments\n• Attendance records\n• Results & grades\n• Timetable & schedule\n• Personal information\n• Tasks & assignments\n• Expenses & charges\n\nAsk me anything about your academic journey!`,
      timestamp: new Date().toISOString(),
      isSystem: true
    };
    
    setMessages([welcomeMessage]);
    
    // Load suggestions based on student context
    loadChatSuggestions(studentData);
  };

  const loadChatSuggestions = (studentData) => {
    const defaultSuggestions = [
      "What is my academic progress?",
      "Show my fee details",
      "What is my attendance percentage?",
      "Check my recent results",
      "What is my timetable?",
      "Show my personal information",
      "What are my pending tasks?",
      "Check my university expenses",
      "Am I eligible to graduate?",
      "What courses am I taking?"
    ];
    
    // Context-aware suggestions
    if (studentData?.student?.scholarship?.isApplicant) {
      defaultSuggestions.push("What is my scholarship amount?");
    }
    
    if (studentData?.academicProgress?.completionPercentage > 75) {
      defaultSuggestions.push("When will I graduate?");
    }
    
    setSuggestions(defaultSuggestions);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  // In your frontend handleSendMessage function:
const handleSendMessage = async (message = userInput) => {
    if (!message.trim() || isAiTyping) return;

    const userMessage = message.trim();
    setUserInput('');
    
    // Add user message to chat with enhanced styling
    const newUserMessage = {
        id: Date.now(),
        type: 'user',
        content: userMessage,
        timestamp: new Date().toISOString(),
        isTyping: false
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsAiTyping(true);

    try {
        console.log('🚀 Sending message to chatbot...');
        console.log('📋 Question:', userMessage);
        console.log('👤 Current Student:', payload?.student?.studentId);
        console.log('👤 Student Name:', payload?.student?.name?.fullName);
        
        // Get student context
        const studentContext = {
            studentId: payload?.student?.studentId,
            studentName: payload?.student?.name?.fullName,
            currentSemester: payload?.academicProgress?.currentSemester,
            department: payload?.student?.department
        };
        
        console.log('📊 Student Context:', studentContext);
        
        // Make API call with proper error handling
        const response = await axios.post(`${CHATBOT_API_URL}/query`, 
            { 
                question: userMessage
                // Note: studentId comes from session via cookies/authentication middleware
            },
            { 
                withCredentials: true,
                timeout: 45000, // 45 second timeout for complex queries
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                validateStatus: function (status) {
                    return status < 500; // Resolve only if status code is less than 500
                }
            }
        );

        console.log('✅ Chatbot API Response:', response.status);
        console.log('📦 Response Data:', response.data);
        
        if (!response.data.success) {
            throw new Error(response.data.text || response.data.message || 'Chatbot service error');
        }

        // Format the AI response
        const aiMessage = {
            id: Date.now() + 1,
            type: 'ai',
            content: response.data.text || response.data.answer || 
                    "I don't have an answer for that at the moment.",
            data: response.data.data,
            metadata: response.data.metadata || {},
            suggestions: response.data.suggestions || [
                "What is my academic progress?",
                "Show my fee details",
                "What is my attendance percentage?",
                "Check my recent results"
            ],
            timestamp: new Date().toISOString(),
            isAIEnhanced: response.data.metadata?.isAIEnhanced || false,
            isConversational: response.data.metadata?.isContextAware || false
        };

        // Add AI message to chat
        setMessages(prev => [...prev, aiMessage]);
        
        // Update suggestions if provided
        if (response.data.suggestions && response.data.suggestions.length > 0) {
            setSuggestions(response.data.suggestions);
        }
        
        // Update chat history
        setChatHistory(prev => [
            ...prev.slice(-9), // Keep last 10 conversations
            { 
                question: userMessage, 
                answer: response.data.text,
                intent: response.data.metadata?.intent || 'unknown',
                confidence: response.data.metadata?.confidence || 0,
                timestamp: new Date().toISOString(),
                studentId: response.data.metadata?.studentId || payload?.student?.studentId
            }
        ]);

        // Log successful interaction
        console.log(`🎉 Chat successful: ${response.data.metadata?.intent || 'unknown'} intent`);
        console.log(`⏱️ Response time: ${response.data.metadata?.responseTime || 'N/A'}ms`);
        console.log(`📊 Records found: ${response.data.metadata?.recordsFound || 0}`);

    } catch (error) {
        console.error('❌ Chatbot API error:', error);
        console.error('Error response:', error.response?.data);
        console.error('Error status:', error.response?.status);
        
        // Determine error message based on error type
        let errorMessage = "I'm having trouble connecting right now. ";
        let errorSuggestions = [
            "Try asking about your academic progress",
            "Check your fee details",
            "View your attendance records"
        ];
        
        if (error.response) {
            // Server responded with error status
            switch (error.response.status) {
                case 401:
                    errorMessage = "You need to log in again to use the chatbot. Please refresh the page.";
                    errorSuggestions = ["Refresh the page", "Log out and log back in"];
                    break;
                case 429:
                    errorMessage = "You're sending messages too quickly. Please wait a moment.";
                    errorSuggestions = ["Wait 30 seconds", "Try again in a minute"];
                    break;
                case 500:
                    errorMessage = "The chatbot service is having issues. Please try again in a moment.";
                    errorSuggestions = ["Try again in a minute", "Contact support if issue persists"];
                    break;
                case 504:
                    errorMessage = "The request is taking too long. Please try a simpler question.";
                    errorSuggestions = ["Ask a simpler question", "Try again later"];
                    break;
                default:
                    if (error.response.data?.text) {
                        errorMessage = error.response.data.text;
                    }
            }
        } else if (error.request) {
            // Request was made but no response
            errorMessage = "Cannot connect to the chatbot server. Please check your internet connection.";
            errorSuggestions = ["Check your internet", "Try again later"];
        } else {
            // Something else happened
            errorMessage = `Error: ${error.message}. Please try again.`;
        }
        
        // Add AI error message to chat
        const errorMessageObj = {
            id: Date.now() + 1,
            type: 'ai',
            content: errorMessage + "\n\nYou can try:\n• Asking about a different topic\n• Checking your dashboard directly\n• Contacting support if the issue continues",
            timestamp: new Date().toISOString(),
            isError: true,
            suggestions: errorSuggestions
        };
        
        setMessages(prev => [...prev, errorMessageObj]);
        
        // Update suggestions with error-specific suggestions
        setSuggestions(errorSuggestions);
        
    } finally {
        setIsAiTyping(false);
        
        // Auto-scroll to bottom after message
        setTimeout(() => {
            scrollToBottom();
        }, 100);
    }
};

  const handleQuickAction = (action) => {
    switch(action) {
      case 'fees':
        handleSendMessage("What are my fee details?");
        break;
      case 'attendance':
        handleSendMessage("What is my attendance percentage?");
        break;
      case 'schedule':
        handleSendMessage("What is my timetable?");
        break;
      case 'assignments':
        handleSendMessage("What assignments do I have?");
        break;
      case 'gpa':
        handleSendMessage("What is my current GPA?");
        break;
      case 'progress':
        handleSendMessage("What is my academic progress?");
        break;
      case 'scholarship':
        handleSendMessage("What is my scholarship amount?");
        break;
      case 'graduation':
        handleSendMessage("Am I eligible to graduate?");
        break;
      default:
        handleSendMessage(action);
    }
  };

  const clearChat = async () => {
    try {
      // Optional: Call backend to clear history
      await axios.post(`${CHATBOT_API_URL}/clear`, {}, { withCredentials: true });
    } catch (error) {
      console.log('Note: Could not clear backend chat history');
    }
    
    // Clear local messages
    setMessages([]);
    
    // Re-initialize with welcome message if we have student data
    if (payload) {
      initializeChatbotWithContext(payload);
    } else {
      setMessages([{
        id: Date.now(),
        type: 'ai',
        content: "Hello! I'm your Student Assistant. How can I help you today?",
        timestamp: new Date().toISOString(),
        isSystem: true
      }]);
    }
  };

  const getDashboardInsights = () => {
    if (!payload) return [];
    
    const insights = [];
    const { academicProgress, student } = payload;
    
    // GPA insight
    if (academicProgress.cumulativeGPA && academicProgress.cumulativeGPA < 2.0) {
      insights.push({
        type: 'warning',
        icon: <AlertCircle size={16} />,
        text: 'Your GPA is below 2.0. Consider meeting with your advisor.',
        action: () => handleQuickAction('progress')
      });
    }
    
    // Scholarship insight
    if (student.scholarship?.isApplicant && student.scholarship?.percentage > 0) {
      insights.push({
        type: 'success',
        icon: <TrendingUp size={16} />,
        text: `You have a ${student.scholarship.percentage}% scholarship. Keep up the good work!`,
        action: () => handleQuickAction('scholarship')
      });
    }
    
    // Progress insight
    if (academicProgress.completionPercentage > 75) {
      insights.push({
        type: 'info',
        icon: <CheckCircle size={16} />,
        text: `Great progress! You've completed ${academicProgress.completionPercentage}% of your degree.`,
        action: () => handleQuickAction('graduation')
      });
    }
    
    // Credits insight
    if (academicProgress.totalCreditsEarned > 0) {
      const creditsPercentage = (academicProgress.totalCreditsEarned / academicProgress.totalCreditsRequired) * 100;
      if (creditsPercentage > 90) {
        insights.push({
          type: 'success',
          icon: <CheckCircle size={16} />,
          text: `Almost there! You've earned ${academicProgress.totalCreditsEarned}/${academicProgress.totalCreditsRequired} credits.`,
          action: () => handleQuickAction('progress')
        });
      }
    }
    
    return insights.slice(0, 3);
  };

  const formatMessageContent = (content) => {
    if (!content) return content;
    
    return content.split('\n').map((line, index) => {
      if (line.startsWith('• ') || line.startsWith('📚') || line.startsWith('💰') || 
          line.startsWith('📊') || line.startsWith('🎓') || line.startsWith('👤')) {
        return <p key={index} className="message-line-emphasis">{line}</p>;
      }
      if (line.startsWith('  • ')) {
        return <p key={index} className="message-line-indent">{line}</p>;
      }
      return <p key={index}>{line}</p>;
    });
  };

  const renderMessageData = (data) => {
    if (!data) return null;
    
    if (typeof data === 'object') {
      return (
        <div className="message-data">
          <details>
            <summary>📊 View Details</summary>
            <pre>{JSON.stringify(data, null, 2)}</pre>
          </details>
        </div>
      );
    }
    
    return null;
  };

  // Test chatbot connection
  const testChatbotConnection = async () => {
    try {
      console.log('Testing chatbot connection...');
      const response = await axios.get(`${CHATBOT_API_URL}/test`);
      console.log('Chatbot test response:', response.data);
      return true;
    } catch (error) {
      console.error('Chatbot connection test failed:', error);
      return false;
    }
  };

  // Call this when component mounts
  useEffect(() => {
    if (chatbotOpen) {
      testChatbotConnection();
    }
  }, [chatbotOpen]);

  if (loading) {
    return (
      <div className="loader-container">
        <Loader2 className="loader-icon" />
        <p>Loading your dashboard...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="error-container">
        <AlertCircle size={48} />
        <h3>Unable to Load Dashboard</h3>
        <p>{error}</p>
        <button onClick={loadDashboard} className="retry-btn">
          <RefreshCw size={16} /> Try Again
        </button>
      </div>
    );
  }

  if (!payload) {
    return (
      <div className="error-container">
        <AlertCircle size={48} />
        <h3>No Data Available</h3>
        <p>Unable to load student information.</p>
        <button onClick={loadDashboard} className="retry-btn">
          <RefreshCw size={16} /> Retry
        </button>
      </div>
    );
  }

  const { student, academicProgress } = payload;
  const current = academicProgress.currentSemesterDetails || {};
  const percentProgress = Math.min(
    100,
    Math.round((academicProgress.totalCreditsEarned / Math.max(1, academicProgress.totalCreditsRequired)) * 100)
  );
  
  const insights = getDashboardInsights();

  return (
    <div className="dashboard-container">
      {/* Chatbot Widget */}
      <div className={`chatbot-widget ${chatbotOpen ? 'open' : ''}`}>
        {/* Chatbot Toggle Button */}
        <button 
          className="chatbot-toggle-btn"
          onClick={() => setChatbotOpen(!chatbotOpen)}
          aria-label={chatbotOpen ? "Close chatbot" : "Open chatbot"}
        >
          {chatbotOpen ? <X size={20} /> : <MessageSquare size={20} />}
          {!chatbotOpen && messages.length > 1 && (
            <span className="chat-notification">{messages.length - 1}</span>
          )}
        </button>

        {/* Chatbot Interface */}
        <div className="chatbot-interface">
          {/* Chat Header */}
          <div className="chat-header">
            <div className="chat-header-info">
              <Bot size={24} className="chat-header-icon" />
              <div>
                <h3>Student Assistant</h3>
                <p className="chat-subtitle">AI-powered academic helper</p>
              </div>
            </div>
            <div className="chat-header-actions">
              <button 
                className="chat-action-btn" 
                onClick={clearChat}
                title="Clear chat history"
              >
                <Trash2 size={16} />
              </button>
            </div>
          </div>

          {/* Chat Messages */}
          <div className="chat-messages-container" ref={chatContainerRef}>
            {messages.map((message) => (
              <div 
                key={message.id} 
                className={`chat-message ${message.type} ${message.isSystem ? 'system' : ''} ${message.isError ? 'error' : ''}`}
              >
                <div className="message-avatar">
                  {message.type === 'ai' ? <Bot size={18} /> : <User size={18} />}
                </div>
                <div className="message-content-wrapper">
                  <div className="message-content">
                    <div className="message-text">
                      {formatMessageContent(message.content)}
                    </div>
                    {message.data && renderMessageData(message.data)}
                  </div>
                  <div className="message-meta">
                    <span className="message-time">
                      {new Date(message.timestamp).toLocaleTimeString([], { 
                        hour: '2-digit', 
                        minute: '2-digit' 
                      })}
                    </span>
                    {message.metadata?.processingTime && (
                      <span className="message-processing">
                        <Clock size={12} /> {message.metadata.processingTime}ms
                      </span>
                    )}
                  </div>
                </div>
              </div>
            ))}
            
            {isAiTyping && (
              <div className="chat-message ai typing">
                <div className="message-avatar">
                  <Bot size={18} />
                </div>
                <div className="message-content-wrapper">
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>

          {/* Quick Actions */}
          <div className="quick-actions">
            <button 
              className="quick-action-btn"
              onClick={() => handleQuickAction('fees')}
            >
              <CreditCard size={16} /> Fees
            </button>
            <button 
              className="quick-action-btn"
              onClick={() => handleQuickAction('attendance')}
            >
              <TrendingUp size={16} /> Attendance
            </button>
            <button 
              className="quick-action-btn"
              onClick={() => handleQuickAction('schedule')}
            >
              <Calendar size={16} /> Schedule
            </button>
            <button 
              className="quick-action-btn"
              onClick={() => handleQuickAction('assignments')}
            >
              <BookOpen size={16} /> Tasks
            </button>
          </div>

          {/* Suggestions */}
          {suggestions.length > 0 && (
            <div className="suggestions-container">
              <p className="suggestions-title">Try asking:</p>
              <div className="suggestions-grid">
                {suggestions.slice(0, 4).map((suggestion, index) => (
                  <button
                    key={index}
                    className="suggestion-chip"
                    onClick={() => handleQuickAction(suggestion)}
                  >
                    {suggestion}
                    <ChevronRight size={14} />
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Chat Input */}
          <div className="chat-input-area">
            <input
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && !e.shiftKey && handleSendMessage()}
              placeholder="Ask about fees, grades, schedule, etc..."
              disabled={isAiTyping}
              className="chat-input-field"
              aria-label="Chat input"
            />
            <button 
              className="send-message-btn"
              onClick={() => handleSendMessage()}
              disabled={!userInput.trim() || isAiTyping}
              aria-label="Send message"
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Dashboard Content */}
      <div className="dashboard-content">
        {/* Insights Section */}
        {insights.length > 0 && (
          <div className="insights-section">
            <h3 className="insights-title">Insights</h3>
            <div className="insights-grid">
              {insights.map((insight, index) => (
                <div 
                  key={index} 
                  className={`insight-card ${insight.type}`}
                  onClick={insight.action}
                  role="button"
                  tabIndex={0}
                >
                  <div className="insight-icon-wrapper">{insight.icon}</div>
                  <div className="insight-text-content">{insight.text}</div>
                  <ChevronRight size={16} className="insight-arrow" />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Main Dashboard Header */}
        <header className="dashboard-header">
          <div className="student-profile">
            <div className="student-avatar">
              {student.photoPath ? (
                <img 
                  src={`${API_BASE_URL}/${student.photoPath}`} 
                  alt={student.name.fullName} 
                  className="avatar-image"
                />
              ) : (
                <div className="avatar-placeholder">
                  {student.name.fullName?.charAt(0)?.toUpperCase() || 'S'}
                </div>
              )}
            </div>
            <div className="student-info">
              <h1 className="student-name">{student.name.fullName}</h1>
              <div className="student-id">{student.studentId}</div>
              <div className="student-details">
                <span className="detail-item">{student.departmentCode} {student.department}</span>
                <span className="detail-item">{student.universityEmail}</span>
                <span className="detail-item">{student.contactNumber}</span>
              </div>
              <div className="student-badges">
                <span className="badge">{student.degreeLevel}</span>
                <span className="badge">Section {student.section}</span>
                {student.scholarship?.isApplicant && (
                  <span className="badge scholarship">Scholarship {student.scholarship.percentage}%</span>
                )}
              </div>
            </div>
          </div>

          <div className="academic-stats">
            <div className="stat-card">
              <div className="stat-label">Cumulative GPA</div>
              <div className="stat-value">{academicProgress.cumulativeGPA?.toFixed(2) || '-'}</div>
            </div>
            <div className="stat-card">
              <div className="stat-label">Total Credits</div>
              <div className="stat-value">
                {academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-label">Progress</div>
              <div className="stat-value">{academicProgress.completionPercentage || percentProgress}%</div>
            </div>
          </div>
        </header>

        {/* Summary Cards */}
        <section className="summary-cards">
          <div className="summary-card">
            <h3 className="card-title">Degree Progress</h3>
            <div className="progress-container">
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ width: `${percentProgress}%` }}
                />
              </div>
              <div className="progress-text">
                <span>{academicProgress.totalCreditsEarned} of {academicProgress.totalCreditsRequired} credits completed</span>
                <span>{percentProgress}%</span>
              </div>
            </div>
            <div className="card-footer">
              <span className="footer-text">
                Scholarship: {student.scholarship?.isApplicant ? `${student.scholarship.percentage}%` : 'Not applicable'}
              </span>
            </div>
          </div>

          <div className="summary-card">
            <h3 className="card-title">Current Semester (Semester {academicProgress.currentSemester})</h3>
            <div className="metrics-grid">
              <div className="metric">
                <div className="metric-label">Semester GPA</div>
                <div className="metric-value">{current.semesterGPA?.toFixed(2) || '-'}</div>
              </div>
              <div className="metric">
                <div className="metric-label">Credits Attempted</div>
                <div className="metric-value">{current.creditsAttempted || 0}</div>
              </div>
              <div className="metric">
                <div className="metric-label">Credits Earned</div>
                <div className="metric-value">{current.creditsEarned || 0}</div>
              </div>
              <div className="metric">
                <div className="metric-label">Quality Points</div>
                <div className="metric-value">{current.qualityPoints || 0}</div>
              </div>
            </div>
            {current.startDate && (
              <div className="card-footer">
                <span className="footer-text">
                  Period: {new Date(current.startDate).toLocaleDateString()} - {new Date(current.endDate).toLocaleDateString()}
                </span>
              </div>
            )}
          </div>

          <div className="summary-card">
            <h3 className="card-title">Quick Actions</h3>
            <div className="action-buttons">
              <button 
                className="action-button primary"
                onClick={() => handleQuickAction('fees')}
              >
                <CreditCard size={16} /> Check Fees
              </button>
              <button 
                className="action-button primary"
                onClick={() => handleQuickAction('schedule')}
              >
                <Calendar size={16} /> Today's Schedule
              </button>
              <button 
                className="action-button secondary"
                onClick={() => setShowAllSemesters(!showAllSemesters)}
              >
                {showAllSemesters ? 'Hide' : 'Show'} All Semesters
              </button>
              <button 
                className="action-button ghost"
                onClick={loadDashboard}
              >
                <RefreshCw size={16} /> Refresh
              </button>
            </div>
            <div className="card-footer">
              <span className="footer-text">Chat with AI Assistant for detailed queries</span>
            </div>
          </div>
        </section>

        {/* Current Courses Section */}
        <section className="courses-section">
          <h2 className="section-title">Current Semester Courses</h2>
          <div className="courses-grid">
            {(current.courses || []).length === 0 ? (
              <div className="empty-state">No courses found for current semester</div>
            ) : (
              current.courses.map((course, index) => (
                <div key={index} className="course-card">
                  <div className="course-header">
                    <div className="course-code">{course.courseCode || '—'}</div>
                    <div className="course-meta">
                      <span className={`course-status ${course.status?.toLowerCase()}`}>
                        {course.status || 'N/A'}
                      </span>
                      <span className="course-grade">{course.grade || '-'}</span>
                    </div>
                  </div>
                  <div className="course-body">
                    <h4 className="course-name">{course.courseName || 'Untitled Course'}</h4>
                    <div className="course-details">
                      <span className="detail">Credits: {course.creditsEarned || 0}</span>
                      {course.attendance && (
                        <span className="detail">Attendance: {course.attendance}%</span>
                      )}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </section>

        {/* All Semesters Section */}
        {showAllSemesters && (
          <section className="semesters-section">
            <h2 className="section-title">All Semesters</h2>
            <div className="semesters-table">
              <div className="table-header">
                <div className="table-cell">Semester</div>
                <div className="table-cell">Status</div>
                <div className="table-cell">GPA</div>
                <div className="table-cell">Credits</div>
                <div className="table-cell">Period</div>
                <div className="table-cell">Courses</div>
              </div>
              {(academicProgress.allSemesters || []).map((semester, index) => (
                <div key={index} className="table-row">
                  <div className="table-cell">{semester.semesterNumber}</div>
                  <div className="table-cell">
                    <span className={`status-badge ${semester.status}`}>
                      {semester.status}
                    </span>
                  </div>
                  <div className="table-cell">{semester.semesterGPA?.toFixed(2) || '-'}</div>
                  <div className="table-cell">
                    {semester.creditsEarned}/{semester.creditsAttempted}
                  </div>
                  <div className="table-cell">
                    {semester.startDate ? 
                      `${new Date(semester.startDate).toLocaleDateString()} - ${new Date(semester.endDate).toLocaleDateString()}` 
                      : '-'
                    }
                  </div>
                  <div className="table-cell courses-cell">
                    {(semester.courses || []).slice(0, 3).map((course, idx) => (
                      <div key={idx} className="course-item">
                        <strong>{course.courseCode}</strong> • {course.courseName} • {course.grade || '-'}
                      </div>
                    ))}
                    {semester.courses && semester.courses.length > 3 && (
                      <div className="more-courses">+{semester.courses.length - 3} more</div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}
      </div>

      {/* CSS Styles */}
      <style jsx>{`
        .dashboard-container {
          position: relative;
          min-height: 100vh;
          background: #f8fafc;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
        }

        /* Chatbot Widget */
        .chatbot-widget {
          position: fixed;
          bottom: 24px;
          right: 24px;
          z-index: 1000;
        }

        .chatbot-toggle-btn {
          width: 60px;
          height: 60px;
          border-radius: 50%;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          border: none;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          box-shadow: 0 8px 32px rgba(102, 126, 234, 0.3);
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          position: relative;
        }

        .chatbot-toggle-btn:hover {
          transform: translateY(-2px) scale(1.05);
          box-shadow: 0 12px 48px rgba(102, 126, 234, 0.4);
        }

        .chat-notification {
          position: absolute;
          top: -5px;
          right: -5px;
          background: #ef4444;
          color: white;
          border-radius: 50%;
          width: 24px;
          height: 24px;
          font-size: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: 600;
          border: 2px solid white;
        }

        .chatbot-interface {
          position: absolute;
          bottom: 80px;
          right: 0;
          width: 420px;
          height: 680px;
          background: white;
          border-radius: 20px;
          box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
          display: flex;
          flex-direction: column;
          opacity: 0;
          transform: translateY(20px) scale(0.95);
          pointer-events: none;
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          overflow: hidden;
        }

        .chatbot-widget.open .chatbot-interface {
          opacity: 1;
          transform: translateY(0) scale(1);
          pointer-events: all;
        }

        .chat-header {
          padding: 20px;
          border-bottom: 1px solid #f1f5f9;
          display: flex;
          justify-content: space-between;
          align-items: center;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .chat-header-info {
          display: flex;
          align-items: center;
          gap: 12px;
        }

        .chat-header h3 {
          margin: 0;
          font-size: 18px;
          font-weight: 600;
        }

        .chat-subtitle {
          margin: 4px 0 0;
          font-size: 13px;
          opacity: 0.9;
        }

        .chat-action-btn {
          background: rgba(255, 255, 255, 0.2);
          border: none;
          color: white;
          width: 36px;
          height: 36px;
          border-radius: 8px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: all 0.2s;
        }

        .chat-action-btn:hover {
          background: rgba(255, 255, 255, 0.3);
        }

        .chat-messages-container {
          flex: 1;
          overflow-y: auto;
          padding: 20px;
          display: flex;
          flex-direction: column;
          gap: 16px;
          background: #f8fafc;
        }

        .chat-message {
          display: flex;
          gap: 12px;
          animation: messageAppear 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        }

        @keyframes messageAppear {
          from {
            opacity: 0;
            transform: translateY(10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .chat-message.user {
          align-self: flex-end;
          flex-direction: row-reverse;
        }

        .message-avatar {
          width: 36px;
          height: 36px;
          border-radius: 50%;
          background: white;
          border: 2px solid #e2e8f0;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
          margin-top: 4px;
        }

        .chat-message.ai .message-avatar {
          background: #667eea;
          border-color: #667eea;
          color: white;
        }

        .chat-message.user .message-avatar {
          background: #10b981;
          border-color: #10b981;
          color: white;
        }

        .message-content-wrapper {
          max-width: 280px;
        }

        .message-content {
          background: white;
          padding: 16px;
          border-radius: 18px;
          border-bottom-left-radius: 4px;
          box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
        }

        .chat-message.user .message-content {
          background: #10b981;
          color: white;
          border-bottom-left-radius: 18px;
          border-bottom-right-radius: 4px;
        }

        .message-text {
          font-size: 14px;
          line-height: 1.5;
          color: #374151;
        }

        .chat-message.user .message-text {
          color: white;
        }

        .message-line-emphasis {
          font-weight: 600;
          margin: 8px 0;
        }

        .message-line-indent {
          margin-left: 20px;
          margin: 4px 0 4px 20px;
        }

        .message-data {
          margin-top: 12px;
          border-top: 1px solid #e5e7eb;
          padding-top: 12px;
        }

        .message-data details {
          font-size: 12px;
        }

        .message-data summary {
          cursor: pointer;
          color: #667eea;
          font-weight: 500;
        }

        .message-data pre {
          margin-top: 8px;
          padding: 12px;
          background: #f9fafb;
          border-radius: 8px;
          font-size: 11px;
          overflow: auto;
          max-height: 200px;
        }

        .message-meta {
          display: flex;
          gap: 8px;
          align-items: center;
          margin-top: 6px;
          font-size: 11px;
          color: #9ca3af;
          padding: 0 4px;
        }

        .chat-message.user .message-meta {
          justify-content: flex-end;
        }

        .message-processing {
          display: flex;
          align-items: center;
          gap: 4px;
        }

        .typing-indicator {
          display: flex;
          gap: 6px;
          padding: 16px 20px;
          background: white;
          border-radius: 18px;
          border-bottom-left-radius: 4px;
        }

        .typing-indicator span {
          width: 8px;
          height: 8px;
          background: #cbd5e1;
          border-radius: 50%;
          animation: typing 1.4s infinite ease-in-out;
        }

        .typing-indicator span:nth-child(2) {
          animation-delay: 0.2s;
        }

        .typing-indicator span:nth-child(3) {
          animation-delay: 0.4s;
        }

        @keyframes typing {
          0%, 60%, 100% { 
            transform: translateY(0); 
            opacity: 0.6;
          }
          30% { 
            transform: translateY(-8px); 
            opacity: 1;
          }
        }

        .quick-actions {
          display: flex;
          gap: 8px;
          padding: 0 20px 16px;
          border-bottom: 1px solid #f1f5f9;
        }

        .quick-action-btn {
          flex: 1;
          padding: 10px 12px;
          background: white;
          border: 1px solid #e5e7eb;
          border-radius: 12px;
          font-size: 13px;
          color: #4b5563;
          cursor: pointer;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 6px;
          transition: all 0.2s;
          font-weight: 500;
        }

        .quick-action-btn:hover {
          background: #f9fafb;
          border-color: #d1d5db;
          transform: translateY(-1px);
        }

        .suggestions-container {
          padding: 16px 20px;
          border-bottom: 1px solid #f1f5f9;
        }

        .suggestions-title {
          font-size: 13px;
          color: #6b7280;
          margin: 0 0 12px;
          font-weight: 500;
        }

        .suggestions-grid {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .suggestion-chip {
          background: #f9fafb;
          border: 1px solid #e5e7eb;
          border-radius: 12px;
          padding: 12px 16px;
          font-size: 14px;
          color: #374151;
          text-align: left;
          cursor: pointer;
          display: flex;
          justify-content: space-between;
          align-items: center;
          transition: all 0.2s;
        }

        .suggestion-chip:hover {
          background: white;
          border-color: #667eea;
          box-shadow: 0 4px 12px rgba(102, 126, 234, 0.1);
          transform: translateX(2px);
        }

        .chat-input-area {
          padding: 20px;
          display: flex;
          gap: 12px;
          background: white;
        }

        .chat-input-field {
          flex: 1;
          padding: 14px 20px;
          border: 2px solid #e5e7eb;
          border-radius: 14px;
          font-size: 14px;
          outline: none;
          transition: all 0.2s;
          background: #f9fafb;
        }

        .chat-input-field:focus {
          border-color: #667eea;
          background: white;
          box-shadow: 0 0 0 4px rgba(102, 126, 234, 0.1);
        }

        .send-message-btn {
          width: 52px;
          height: 52px;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          border: none;
          border-radius: 14px;
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          transition: all 0.2s;
          flex-shrink: 0;
        }

        .send-message-btn:hover:not(:disabled) {
          transform: scale(1.05);
          box-shadow: 0 8px 24px rgba(102, 126, 234, 0.3);
        }

        .send-message-btn:disabled {
          background: #d1d5db;
          cursor: not-allowed;
        }

        /* Dashboard Content */
        .dashboard-content {
          max-width: 1200px;
          margin: 0 auto;
          padding: 32px;
        }

        /* Insights Section */
        .insights-section {
          margin-bottom: 32px;
        }

        .insights-title {
          font-size: 18px;
          font-weight: 600;
          color: #111827;
          margin-bottom: 16px;
        }

        .insights-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
          gap: 16px;
        }

        .insight-card {
          background: white;
          padding: 20px;
          border-radius: 16px;
          border-left: 4px solid;
          display: flex;
          align-items: center;
          gap: 16px;
          cursor: pointer;
          transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
        }

        .insight-card:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
        }

        .insight-card.info {
          border-left-color: #3b82f6;
        }

        .insight-card.warning {
          border-left-color: #f59e0b;
        }

        .insight-card.success {
          border-left-color: #10b981;
        }

        .insight-icon-wrapper {
          width: 40px;
          height: 40px;
          border-radius: 12px;
          display: flex;
          align-items: center;
          justify-content: center;
          flex-shrink: 0;
        }

        .insight-card.info .insight-icon-wrapper {
          background: #dbeafe;
          color: #3b82f6;
        }

        .insight-card.warning .insight-icon-wrapper {
          background: #fef3c7;
          color: #f59e0b;
        }

        .insight-card.success .insight-icon-wrapper {
          background: #d1fae5;
          color: #10b981;
        }

        .insight-text-content {
          flex: 1;
          font-size: 14px;
          color: #4b5563;
          line-height: 1.5;
        }

        .insight-arrow {
          color: #9ca3af;
        }

        /* Dashboard Header */
        .dashboard-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 32px;
          padding: 32px;
          background: white;
          border-radius: 20px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }

        .student-profile {
          display: flex;
          gap: 24px;
          align-items: center;
        }

        .student-avatar {
          width: 100px;
          height: 100px;
          border-radius: 20px;
          overflow: hidden;
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          display: flex;
          align-items: center;
          justify-content: center;
          box-shadow: 0 8px 32px rgba(102, 126, 234, 0.2);
        }

        .avatar-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .avatar-placeholder {
          font-size: 40px;
          font-weight: 700;
          color: white;
        }

        .student-info {
          flex: 1;
        }

        .student-name {
          margin: 0 0 8px;
          font-size: 28px;
          font-weight: 700;
          color: #111827;
        }

        .student-id {
          font-size: 14px;
          color: #6b7280;
          margin-bottom: 12px;
        }

        .student-details {
          display: flex;
          flex-wrap: wrap;
          gap: 16px;
          margin-bottom: 16px;
        }

        .detail-item {
          font-size: 14px;
          color: #4b5563;
          padding: 6px 12px;
          background: #f9fafb;
          border-radius: 8px;
        }

        .student-badges {
          display: flex;
          gap: 8px;
          flex-wrap: wrap;
        }

        .badge {
          padding: 8px 16px;
          background: #e0e7ff;
          color: #3730a3;
          border-radius: 12px;
          font-size: 13px;
          font-weight: 600;
        }

        .badge.scholarship {
          background: #d1fae5;
          color: #065f46;
        }

        .academic-stats {
          display: flex;
          gap: 24px;
        }

        .stat-card {
          padding: 24px;
          background: #f9fafb;
          border-radius: 16px;
          text-align: center;
          min-width: 140px;
        }

        .stat-label {
          font-size: 13px;
          color: #6b7280;
          margin-bottom: 8px;
        }

        .stat-value {
          font-size: 32px;
          font-weight: 700;
          color: #111827;
        }

        /* Summary Cards */
        .summary-cards {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 24px;
          margin-bottom: 32px;
        }

        .summary-card {
          background: white;
          padding: 24px;
          border-radius: 20px;
          box-shadow: 0 8px 32px rgba(0, 0, 0, 0.05);
        }

        .card-title {
          font-size: 18px;
          font-weight: 600;
          color: #111827;
          margin: 0 0 20px;
        }

        .progress-container {
          margin-bottom: 16px;
        }

        .progress-bar {
          height: 12px;
          background: #f3f4f6;
          border-radius: 6px;
          overflow: hidden;
          margin-bottom: 8px;
        }

        .progress-fill {
          height: 100%;
          background: linear-gradient(90deg, #667eea 0%, #764ba2 100%);
          border-radius: 6px;
          transition: width 1s ease-in-out;
        }

        .progress-text {
          display: flex;
          justify-content: space-between;
          font-size: 14px;
          color: #6b7280;
        }

        .metrics-grid {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 16px;
          margin-bottom: 16px;
        }

        .metric {
          text-align: center;
        }

        .metric-label {
          font-size: 12px;
          color: #6b7280;
          margin-bottom: 4px;
        }

        .metric-value {
          font-size: 24px;
          font-weight: 700;
          color: #111827;
        }

        .action-buttons {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }

        .action-button {
          padding: 14px 20px;
          border-radius: 12px;
          font-size: 14px;
          font-weight: 500;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          cursor: pointer;
          transition: all 0.2s;
          border: none;
        }

        .action-button.primary {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
        }

        .action-button.primary:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 24px rgba(102, 126, 234, 0.3);
        }

        .action-button.secondary {
          background: #f3f4f6;
          color: #374151;
        }

        .action-button.secondary:hover {
          background: #e5e7eb;
        }

        .action-button.ghost {
          background: transparent;
          color: #6b7280;
          border: 1px solid #e5e7eb;
        }

        .action-button.ghost:hover {
          background: #f9fafb;
        }

        .card-footer {
          margin-top: 20px;
          padding-top: 16px;
          border-top: 1px solid #f3f4f6;
        }

        .footer-text {
          font-size: 13px;
          color: #6b7280;
        }

        /* Courses Section */
        .courses-section {
          margin-bottom: 32px;
        }

        .section-title {
          font-size: 24px;
          font-weight: 700;
          color: #111827;
          margin: 0 0 24px;
        }

        .courses-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
          gap: 20px;
        }

        .empty-state {
          grid-column: 1 / -1;
          text-align: center;
          padding: 40px;
          background: white;
          border-radius: 16px;
          color: #6b7280;
          font-size: 16px;
        }

        .course-card {
          background: white;
          padding: 24px;
          border-radius: 16px;
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
          transition: all 0.3s;
        }

        .course-card:hover {
          transform: translateY(-4px);
          box-shadow: 0 12px 32px rgba(0, 0, 0, 0.1);
        }

        .course-header {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          margin-bottom: 16px;
        }

        .course-code {
          font-size: 16px;
          font-weight: 700;
          color: #111827;
        }

        .course-meta {
          display: flex;
          flex-direction: column;
          align-items: flex-end;
          gap: 8px;
        }

        .course-status {
          padding: 4px 12px;
          border-radius: 20px;
          font-size: 12px;
          font-weight: 600;
        }

        .course-status.completed {
          background: #d1fae5;
          color: #065f46;
        }

        .course-status.enrolled, .course-status.registered {
          background: #dbeafe;
          color: #1e40af;
        }

        .course-status.in-progress {
          background: #fef3c7;
          color: #92400e;
        }

        .course-grade {
          font-size: 20px;
          font-weight: 700;
          color: #111827;
        }

        .course-body h4 {
          margin: 0 0 12px;
          font-size: 18px;
          font-weight: 600;
          color: #111827;
        }

        .course-details {
          display: flex;
          gap: 16px;
          font-size: 14px;
          color: #6b7280;
        }

        /* Semesters Section */
        .semesters-table {
          background: white;
          border-radius: 16px;
          overflow: hidden;
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
        }

        .table-header, .table-row {
          display: grid;
          grid-template-columns: 80px 100px 80px 100px 200px 1fr;
          gap: 20px;
          padding: 20px;
          align-items: center;
        }

        .table-header {
          background: #f9fafb;
          font-weight: 600;
          color: #374151;
          border-bottom: 2px solid #e5e7eb;
        }

        .table-row {
          border-bottom: 1px solid #f3f4f6;
          transition: background 0.2s;
        }

        .table-row:hover {
          background: #f9fafb;
        }

        .table-cell {
          font-size: 14px;
          color: #4b5563;
        }

        .status-badge {
          padding: 4px 12px;
          border-radius: 12px;
          font-size: 12px;
          font-weight: 600;
        }

        .status-badge.completed {
          background: #d1fae5;
          color: #065f46;
        }

        .status-badge.in-progress {
          background: #fef3c7;
          color: #92400e;
        }

        .status-badge.upcoming {
          background: #e0e7ff;
          color: #3730a3;
        }

        .courses-cell {
          max-height: 120px;
          overflow-y: auto;
        }

        .course-item {
          font-size: 13px;
          margin-bottom: 8px;
          padding: 8px;
          background: #f9fafb;
          border-radius: 8px;
        }

        .more-courses {
          font-size: 12px;
          color: #6b7280;
          text-align: center;
          padding: 8px;
          background: #f3f4f6;
          border-radius: 8px;
        }

        /* Loader and Error States */
        .loader-container, .error-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          height: 100vh;
          text-align: center;
        }

        .loader-icon {
          width: 64px;
          height: 64px;
          color: #667eea;
          animation: spin 2s linear infinite;
        }

        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }

        .error-container {
          color: #ef4444;
        }

        .error-container h3 {
          margin: 24px 0 12px;
          font-size: 24px;
        }

        .error-container p {
          margin: 0 0 24px;
          color: #6b7280;
          max-width: 400px;
        }

        .retry-btn {
          padding: 12px 24px;
          background: #667eea;
          color: white;
          border: none;
          border-radius: 12px;
          font-size: 14px;
          font-weight: 500;
          cursor: pointer;
          display: flex;
          align-items: center;
          gap: 8px;
          transition: all 0.2s;
        }

        .retry-btn:hover {
          background: #5a67d8;
          transform: translateY(-2px);
        }

        /* Responsive Design */
        @media (max-width: 1200px) {
          .summary-cards {
            grid-template-columns: repeat(2, 1fr);
          }
        }

        @media (max-width: 1024px) {
          .dashboard-header {
            flex-direction: column;
            gap: 32px;
            align-items: flex-start;
          }

          .academic-stats {
            width: 100%;
            justify-content: space-between;
          }
        }

        @media (max-width: 768px) {
          .dashboard-content {
            padding: 16px;
          }

          .summary-cards {
            grid-template-columns: 1fr;
          }

          .student-profile {
            flex-direction: column;
            text-align: center;
          }

          .student-details {
            justify-content: center;
          }

          .student-badges {
            justify-content: center;
          }

          .academic-stats {
            flex-direction: column;
            gap: 16px;
          }

          .stat-card {
            min-width: 100%;
          }

          .chatbot-interface {
            width: calc(100vw - 32px);
            right: -16px;
          }

          .table-header, .table-row {
            grid-template-columns: 1fr;
            gap: 12px;
          }

          .table-cell:before {
            content: attr(data-label);
            font-weight: 600;
            color: #374151;
            margin-right: 8px;
          }
        }

        @media (max-width: 480px) {
          .chatbot-interface {
            height: 80vh;
          }

          .quick-actions {
            flex-wrap: wrap;
          }

          .quick-action-btn {
            min-width: calc(50% - 4px);
          }
        }
      `}</style>
    </div>
  );
};

export default StudentDashboard;
